
.script-item {
  background: var(--SmartThemeBlurTintColor);
  border: 1px solid var(--SmartThemeBorderColor);
  border-radius: 6px;
  padding: 12px;
  cursor: pointer;
  transition: all 0.2s ease;
}

.script-item:hover {
  background: var(--SmartThemeEmColor);
  border-color: var(--SmartThemeQuoteColor);
}

.script-item.selected {
  background: var(--SmartThemeQuoteColor);
  border-color: var(--SmartThemeEmColor);
}

.script-item.disabled {
  opacity: 0.6;
}

.script-item-content {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.script-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 12px;
}

.script-info {
  display: flex;
  flex-direction: column;
  gap: 4px;
  flex: 1;
  min-width: 0; /* 防止文字溢出 */
}

.script-name {
  margin: 0;
  font-size: 14px;
  font-weight: 600;
  color: var(--SmartThemeEmColor);
  word-break: break-word;
}

.script-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
}

.script-status {
  color: #888;
  padding: 2px 6px;
  border-radius: 3px;
  background: rgba(0, 0, 0, 0.1);
}

.script-status.enabled {
  color: #4caf50;
  background: rgba(76, 175, 80, 0.1);
}

.script-buttons-count {
  display: flex;
  align-items: center;
  gap: 2px;
  color: #666;
}

.script-actions {
  display: flex;
  gap: 6px;
  align-items: flex-start;
  flex-shrink: 0;
}

.toggle-btn,
.action-btn {
  background: none;
  border: 1px solid var(--SmartThemeBorderColor);
  padding: 6px 8px;
  border-radius: 4px;
  cursor: pointer;
  color: var(--SmartThemeBodyColor);
  transition: all 0.2s ease;
  font-size: 12px;
}

.toggle-btn.enabled {
  color: #4caf50;
  border-color: #4caf50;
}

.action-btn:hover,
.toggle-btn:hover {
  background: rgba(255, 255, 255, 0.1);
}

.action-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.run-btn:not(:disabled):hover {
  color: #4caf50;
  border-color: #4caf50;
}

.menu-btn:hover {
  color: var(--SmartThemeEmColor);
}

.script-description {
  font-size: 13px;
  color: var(--SmartThemeBodyColor);
  opacity: 0.8;
  line-height: 1.4;
  padding: 8px 0;
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
}

.script-preview {
  background: rgba(0, 0, 0, 0.2);
  border-radius: 4px;
  overflow: hidden;
}

.preview-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 12px;
  background: rgba(0, 0, 0, 0.2);
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.preview-label {
  font-size: 12px;
  color: var(--SmartThemeBodyColor);
  font-weight: 500;
}

.preview-close-btn {
  background: none;
  border: none;
  color: #888;
  cursor: pointer;
  padding: 2px 4px;
  font-size: 10px;
}

.preview-close-btn:hover {
  color: var(--SmartThemeEmColor);
}

.preview-code {
  padding: 12px;
  margin: 0;
  font-family: 'Consolas', 'Monaco', 'Courier New', monospace;
  font-size: 11px;
  line-height: 1.4;
  color: #e8e8e8;
  white-space: pre-wrap;
  word-break: break-word;
  max-height: 200px;
  overflow-y: auto;
}

.script-footer {
  display: flex;
  justify-content: center;
  padding-top: 4px;
}

.expand-btn {
  background: none;
  border: 1px solid var(--SmartThemeBorderColor);
  color: var(--SmartThemeBodyColor);
  padding: 4px 12px;
  border-radius: 3px;
  cursor: pointer;
  font-size: 11px;
  transition: all 0.2s ease;
}

.expand-btn:hover {
  background: rgba(255, 255, 255, 0.1);
  border-color: var(--SmartThemeEmColor);
  color: var(--SmartThemeEmColor);
}

/* 代码滚动条 */
.preview-code::-webkit-scrollbar {
  width: 6px;
}

.preview-code::-webkit-scrollbar-track {
  background: rgba(0, 0, 0, 0.2);
}

.preview-code::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.2);
  border-radius: 3px;
}

.preview-code::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.3);
}
