
/* 使用V1的样式 */
.script-item {
  width: 100%;
  border: 1px solid var(--SmartThemeBorderColor);
  border-radius: 10px;
  min-height: 35px;
  display: flex;
  justify-content: space-between;
  flex-wrap: nowrap;
  align-items: center;
  padding: 0 5px;
}

.script-item:has(.script-toggle:not(.enabled)) .script-item-name {
  text-decoration: line-through;
  filter: grayscale(0.5);
}

.script-toggle {
  cursor: pointer;
  padding: 5px;
}

.script-toggle:hover {
  background-color: var(--SmartThemeBlurTintColor);
  border-radius: 5px;
}

.menu_button {
  cursor: pointer;
  padding: 5px;
  margin: 0 2px;
  border-radius: 5px;
}

.menu_button:hover {
  background-color: var(--SmartThemeBlurTintColor);
}

.drag-handle {
  cursor: grab;
  padding: 5px;
  user-select: none;
}

.drag-handle:active {
  cursor: grabbing;
}

.flexGrow {
  flex-grow: 1;
}

.overflow-hidden {
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
}

.marginLeft5 {
  margin-left: 5px;
}

.flex-container {
  display: flex;
}

.flexnowrap {
  flex-wrap: nowrap;
}

.alignItemsCenter {
  align-items: center;
}
