
/* 使用V1的样式 */
.script-folder {
  width: 100%;
  border: 1px solid var(--SmartThemeBorderColor);
  border-radius: 10px;
  min-height: 35px;
  background-color: var(--grey5020a);
}

.folder-header {
  display: flex;
  justify-content: space-between;
  flex-wrap: nowrap;
  align-items: center;
  padding: 0 5px;
  min-height: 35px;
}

.script-folder:has(.folder-script-toggle:not(.enabled)) .folder-name {
  text-decoration: line-through;
  filter: grayscale(0.5);
}

.folder-content {
  padding: 5px;
  border-top: 1px solid var(--SmartThemeBorderColor);
}

.folder-content :deep(.script-item) {
  background-color: var(--SmartThemeBlurTintColor);
  margin-bottom: 5px;
}

.folder-content :deep(.script-item:last-child) {
  margin-bottom: 0;
}

.folder-script-toggle {
  cursor: pointer;
  padding: 5px;
}

.folder-script-toggle:hover {
  background-color: var(--SmartThemeBlurTintColor);
  border-radius: 5px;
}

.folder-edit,
.folder-export,
.folder-move,
.folder-delete,
.folder-toggle {
  cursor: pointer;
  padding: 5px;
  margin: 0 2px;
  border-radius: 5px;
}

.folder-edit:hover,
.folder-export:hover,
.folder-move:hover,
.folder-delete:hover,
.folder-toggle:hover {
  background-color: var(--SmartThemeBlurTintColor);
}

.drag-handle {
  cursor: grab;
  padding: 5px;
  user-select: none;
}

.drag-handle:active {
  cursor: grabbing;
}

.folder-icon {
  color: var(--SmartThemeBodyColor);
}

.flexGrow {
  flex-grow: 1;
}

.overflow-hidden {
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
}

.marginLeft5 {
  margin-left: 5px;
}

.flex-container {
  display: flex;
}

.flexnowrap {
  flex-wrap: nowrap;
}

.alignItemsCenter {
  align-items: center;
}
