
.preset-regex-panel {
  width: 100%;
}

.regex-item {
  width: 100%;
  border: 1px solid var(--SmartThemeBorderColor);
  border-radius: 10px;
  min-height: 35px;
  display: flex;
  justify-content: space-between;
  flex-wrap: nowrap;
  align-items: center;
  padding: 0 5px;
}

.regex-item-name {
  flex: 1;
  padding: 8px;
}

.regex-item-controls {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 5px;
}
